import 'dart:math' as math;

/// Replayable CPU render dimensions for preview/refine/slow-mode passes.
///
/// The CPU renderer uses reduced preview passes while gestures are active and a
/// high-resolution slow-mode pass after refinement. Keeping those dimensions in
/// a pure value object exposes the magic floors/caps and makes tiny viewport
/// edge cases testable without spinning up timers or isolates.
final class CpuRenderResolution {
  const CpuRenderResolution({required this.width, required this.height});

  static const int minInteractiveDimension = 200;
  static const int minSlowModeWidth = 400;
  static const int minSlowModeHeight = 400;
  static const int maxSlowModeWidth = 2160;
  static const int maxSlowModeHeight = 3840;

  final int width;
  final int height;

  factory CpuRenderResolution.forPass({
    required int targetWidth,
    required int targetHeight,
    required double resolutionScale,
  }) {
    return CpuRenderResolution(
      width: _interactiveDimension(
        targetDimension: targetWidth,
        resolutionScale: resolutionScale,
      ),
      height: _interactiveDimension(
        targetDimension: targetHeight,
        resolutionScale: resolutionScale,
      ),
    );
  }

  factory CpuRenderResolution.forSlowMode({
    required int targetWidth,
    required int targetHeight,
  }) {
    return CpuRenderResolution(
      width:
          (targetWidth * 2).clamp(minSlowModeWidth, maxSlowModeWidth).toInt(),
      height: (targetHeight * 2)
          .clamp(minSlowModeHeight, maxSlowModeHeight)
          .toInt(),
    );
  }

  static int _interactiveDimension({
    required int targetDimension,
    required double resolutionScale,
  }) {
    if (!resolutionScale.isFinite || resolutionScale >= 1.0) {
      return targetDimension;
    }
    if (targetDimension <= 0) return targetDimension;

    final lowerBound = math.min(minInteractiveDimension, targetDimension);
    return (targetDimension * resolutionScale)
        .round()
        .clamp(lowerBound, targetDimension)
        .toInt();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';

void main() {
  group('CPU render viewport mapping', () {
    test('keeps opposite edge pixel centers symmetric around pan', () {
      final left = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 0,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );
      final right = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 3,
        y: 1,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(left.x + right.x, closeTo(-1.0, 1e-12));
      expect(left.y + right.y, closeTo(0.5, 1e-12));
    });

    test('rejects sample coordinates outside the full viewport before clamping',
        () {
      expect(
        () => cpuViewportCoordinateForSample(
          panX: -0.5,
          panY: 0.25,
          zoom: 3.0,
          fullWidth: 4,
          fullHeight: 2,
          x: 4,
          y: 0,
          sampleOffsetX: 0.5,
          sampleOffsetY: 0.5,
        ),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.name,
            'name',
            'sample coordinate',
          ),
        ),
      );
    });

    test('rejects tile rectangles outside the full viewport before sampling', () {
      const request = CpuTileRenderRequest(
        moduleId: 'mandelbrot',
        panX: 0.0,
        panY: 0.0,
        zoom: 1.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        fullWidth: 4,
        fullHeight: 4,
        x0: 3,
        y0: 0,
        w: 2,
        h: 1,
        sampleCount: 1,
      );

      expect(
        () => renderCpuTileInIsolate(request),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });

    test('maps a one-pixel frame to the requested pan center', () {
      const request = CpuRenderRequest(
        moduleId: 'mandelbrot',
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        width: 1,
        height: 1,
        sampleCount: 1,
      );

      final frame = renderCpuFrameInIsolate(request);
      final expected = cpuFormulaForModuleId(request.moduleId)(
        request.panX,
        request.panY,
        request.iterations,
        request.bailout,
        Vector2(request.juliaCX, request.juliaCY),
      );

      expect(frame.rgba, hasLength(4));
      expect(frame.rgba[0], expected.$1.clamp(0, 255).round());
      expect(frame.rgba[1], expected.$2.clamp(0, 255).round());
      expect(frame.rgba[2], expected.$3.clamp(0, 255).round());
      expect(frame.rgba[3], 255);
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';
import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';

void main() {
  group('CPU Formula Registry', () {
    test('resolves every escape-time catalog module id', () {
      final unresolved = <String>[];
      for (final cfg in escapeTimeCatalog) {
        final formula = cpuFormulaForModuleId(cfg.id);
        final color = formula(0.0, 0.0, 32, 4.0, Vector2.zero());
        final valid =
            color.$1.isFinite && color.$2.isFinite && color.$3.isFinite;
        if (!valid) {
          unresolved.add(cfg.id);
        }
      }
      expect(
        unresolved,
        isEmpty,
        reason:
            'CPU formula resolver produced invalid output for: ${unresolved.join(', ')}',
      );
    });

    test('non-mandelbrot formulas differ from Mandelbrot baseline', () async {
      const width = 64;
      const height = 64;

      // One standard view for consistent comparisons.
      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 3.0;
      const iterations = 80;
      const bailout = 4.0;
      final juliaC = Vector2(-0.8, 0.156);

      final baseline = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: viewPan,
        viewZoom: viewZoom,
        iterations: iterations,
        bailout: bailout,
        juliaC: juliaC,
        width: width,
        height: height,
        sampleCount: 1,
      );

      for (final cfg in escapeTimeCatalog) {
        if (cfg.id == 'mandelbrot') continue;

        final frame = await renderCpuFrame(
          moduleId: cfg.id,
          viewPan: viewPan,
          viewZoom: viewZoom,
          iterations: iterations,
          bailout: bailout,
          juliaC: juliaC,
          width: width,
          height: height,
          sampleCount: 1,
        );

        int diff = 0;
        final total = width * height;
        for (int i = 0; i < frame.rgba.length; i += 4) {
          final dr = (frame.rgba[i] - baseline.rgba[i]).abs();
          final dg = (frame.rgba[i + 1] - baseline.rgba[i + 1]).abs();
          final db = (frame.rgba[i + 2] - baseline.rgba[i + 2]).abs();
          if (dr + dg + db >= 10) diff++;
        }

        final ratio = diff / total;
        expect(
          ratio,
          greaterThan(0.05),
          reason:
              'CPU formula for ${cfg.id} is too similar to Mandelbrot baseline (diffRatio=${ratio.toStringAsFixed(3)}).',
        );
      }
    }, timeout: const Timeout(Duration(minutes: 2)));

    test('renders non-black ratio above 1%', () async {
      const width = 64;
      const height = 64;

      final viewPan = Vector2(-0.5, 0.0);
      const viewZoom = 3.0;
      const iterations = 80;
      const bailout = 4.0;
      final juliaC = Vector2(-0.8, 0.156);

      for (final cfg in escapeTimeCatalog) {
        final frame = await renderCpuFrame(
          moduleId: cfg.id,
          viewPan: viewPan,
          viewZoom: viewZoom,
          iterations: iterations,
          bailout: bailout,
          juliaC: juliaC,
          width: width,
          height: height,
          sampleCount: 1,
        );

        int nonBlack = 0;
        for (int i = 0; i < frame.rgba.length; i += 4) {
          if (frame.rgba[i] > 8 ||
              frame.rgba[i + 1] > 8 ||
              frame.rgba[i + 2] > 8) {
            nonBlack++;
          }
        }
        final ratio = nonBlack / (width * height);
        expect(
          ratio,
          greaterThan(0.01),
          reason:
              '${cfg.id} produced too many black pixels (nonBlackRatio=${ratio.toStringAsFixed(3)}).',
        );
      }
    }, timeout: const Timeout(Duration(minutes: 2)));
  });
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';

const bool kForceCpuFallback =
    bool.fromEnvironment('FORCE_CPU_FALLBACK', defaultValue: false);
// Android emulator GPU is allowed in auto mode. Runtime health probes in
// FractalViewerScreen enforce fast fallback to CPU on invalid output.

enum RendererBackend { gpu, cpu }

enum FallbackReasonCode {
  none,
  forcedByFlag,
  androidEmulator,
  gpuHealthCheckFailed,
  deepZoomPrecision,
  manualToggle,
  moduleUnsupported,
}

class BackendDecision {
  final RendererBackend backend;
  final FallbackReasonCode reasonCode;
  final String detail;

  const BackendDecision({
    required this.backend,
    required this.reasonCode,
    required this.detail,
  });

  bool get isFallback => backend == RendererBackend.cpu;

  String get reasonToken {
    switch (reasonCode) {
      case FallbackReasonCode.none:
        return 'none';
      case FallbackReasonCode.forcedByFlag:
        return 'forced_by_flag';
      case FallbackReasonCode.androidEmulator:
        return 'android_emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'gpu_health_check_failed';
      case FallbackReasonCode.deepZoomPrecision:
        return 'deep_zoom_precision';
      case FallbackReasonCode.manualToggle:
        return 'manual_toggle';
      case FallbackReasonCode.moduleUnsupported:
        return 'module_unsupported';
    }
  }

  String toLogLine({required String moduleId}) {
    return '[renderer] backend_decision backend=${backend.name} reason=$reasonToken module=$moduleId detail=$detail';
  }

  String toUserStatusText() {
    if (!isFallback) return 'Renderer: GPU';
    switch (reasonCode) {
      case FallbackReasonCode.androidEmulator:
        return 'Using stable renderer for this Android emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'GPU output unavailable, using stable renderer';
      case FallbackReasonCode.deepZoomPrecision:
        return 'Deep zoom precision mode enabled';
      case FallbackReasonCode.manualToggle:
        return 'Renderer preference applied';
      case FallbackReasonCode.moduleUnsupported:
        return 'Stable renderer enabled for this fractal mode';
      case FallbackReasonCode.forcedByFlag:
        return 'Stable renderer forced by launch flag';
      case FallbackReasonCode.none:
        return 'Renderer: CPU';
    }
  }
}

class BackendPolicyInput {
  final bool isAndroid;
  final bool isWeb;
  final bool isEmulator;
  final RendererBackendMode userMode;
  final bool gpuHealthFailed;
  final bool deepZoomNeedsCpu;
  final FractalDimension dimension;

  const BackendPolicyInput({
    required this.isAndroid,
    required this.isWeb,
    required this.isEmulator,
    required this.userMode,
    required this.gpuHealthFailed,
    required this.deepZoomNeedsCpu,
    required this.dimension,
  });
}

/// Replayable explanation for the backend rule selected by the policy.
///
/// Platform probes are currently advisory in auto mode: Android emulator status
/// is logged and passed through, but runtime health checks decide fallback.
/// Keeping the selected rule visible makes that precedence testable instead of
/// hiding it in early returns.
class BackendPolicyResolution {
  final BackendDecision decision;
  final String selectedRule;
  final bool platformSignalsUsed;

  const BackendPolicyResolution({
    required this.decision,
    required this.selectedRule,
    required this.platformSignalsUsed,
  });
}

class RendererBackendPolicy {
  const RendererBackendPolicy();

  BackendDecision decide(BackendPolicyInput input) => explain(input).decision;

  BackendPolicyResolution explain(BackendPolicyInput input) {
    if (kForceCpuFallback) {
      return const BackendPolicyResolution(
        selectedRule: 'force_cpu_flag',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.forcedByFlag,
          detail: 'FORCE_CPU_FALLBACK=true',
        ),
      );
    }

    if (input.dimension != FractalDimension.twoD) {
      // 3D modules (e.g. Mandelbulb/Mandelbox) currently rely on GPU shader
      // rendering. Forcing CPU here only produces a disabled placeholder pane.
      // Keep these modules on GPU by default.
      if (input.userMode == RendererBackendMode.cpuOnly) {
        return const BackendPolicyResolution(
          selectedRule: 'gpu_required_module_cpu_only_ignored',
          platformSignalsUsed: false,
          decision: BackendDecision(
            backend: RendererBackend.gpu,
            reasonCode: FallbackReasonCode.moduleUnsupported,
            detail: 'cpu_only_ignored_for_3d_gpu_required',
          ),
        );
      }
      return const BackendPolicyResolution(
        selectedRule: 'gpu_required_module',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.none,
          detail: '3d_gpu_path',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.cpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_cpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'cpu_only',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.gpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_gpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'gpu_only',
        ),
      );
    }

    // Emulator targets are handled like physical devices in auto mode.
    // Runtime GPU health checks own fallback decisions.

    if (input.gpuHealthFailed) {
      return const BackendPolicyResolution(
        selectedRule: 'gpu_health_failed',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.gpuHealthCheckFailed,
          detail: 'frame_probe_detected_invalid_gpu_output',
        ),
      );
    }

    if (input.deepZoomNeedsCpu) {
      return const BackendPolicyResolution(
        selectedRule: 'deep_zoom_precision',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.deepZoomPrecision,
          detail: 'deep_zoom_precision_policy',
        ),
      );
    }

    return const BackendPolicyResolution(
      selectedRule: 'healthy_gpu_target',
      platformSignalsUsed: false,
      decision: BackendDecision(
        backend: RendererBackend.gpu,
        reasonCode: FallbackReasonCode.none,
        detail: 'healthy_gpu_target',
      ),
    );
  }
}

/// Replayable Android emulator signal snapshot.
///
/// Device probing is intentionally best-effort and IO-heavy; keeping the
/// signal classifier pure makes marker drift testable without touching
/// `/proc`, `getprop`, or `/system` in unit tests.
class AndroidEmulatorSignals {
  final String cpuInfo;
  final String hardware;
  final String buildCharacteristics;
  final String productModel;
  final String buildProp;

  const AndroidEmulatorSignals({
    this.cpuInfo = '',
    this.hardware = '',
    this.buildCharacteristics = '',
    this.productModel = '',
    this.buildProp = '',
  });

  bool get isEmulator =>
      AndroidEmulatorMarkerCatalog.hasCpuInfoMarker(cpuInfo) ||
      AndroidEmulatorMarkerCatalog.hasHardwareMarker(hardware) ||
      AndroidEmulatorMarkerCatalog.hasBuildCharacteristicsMarker(
        buildCharacteristics,
      ) ||
      AndroidEmulatorMarkerCatalog.hasProductModelMarker(productModel) ||
      AndroidEmulatorMarkerCatalog.hasBuildPropMarker(buildProp);
}

/// Named emulator marker contract used by Android emulator signal detection.
///
/// The markers are intentionally conservative: substring checks are used only
/// for fields that can contain labels or full property files, while the direct
/// `ro.hardware` value must match a known virtual hardware token exactly.
class AndroidEmulatorMarkerCatalog {
  static const List<String> cpuInfoSubstrings = [
    'ranchu',
    'goldfish',
    'qemu',
    'android virtual processor',
  ];
  static const List<String> exactHardwareValues = ['ranchu', 'goldfish'];
  static const List<String> buildCharacteristicsSubstrings = ['emulator'];
  static const List<String> productModelSubstrings = [
    'sdk_gphone',
    'android sdk built for',
  ];
  static const List<String> buildPropSubstrings = [
    'ro.hardware=goldfish',
    'ro.hardware=ranchu',
    'sdk_gphone',
    'generic_x86',
  ];

  const AndroidEmulatorMarkerCatalog._();

  static bool hasCpuInfoMarker(String value) {
    return _containsAny(value, cpuInfoSubstrings);
  }

  static bool hasHardwareMarker(String value) {
    return exactHardwareValues.contains(value.trim().toLowerCase());
  }

  static bool hasBuildCharacteristicsMarker(String value) {
    return _containsAny(value, buildCharacteristicsSubstrings);
  }

  static bool hasProductModelMarker(String value) {
    return _containsAny(value, productModelSubstrings);
  }

  static bool hasBuildPropMarker(String value) {
    return _containsAny(value, buildPropSubstrings);
  }

  static bool _containsAny(String value, List<String> markers) {
    final normalized = value.toLowerCase();
    return markers.any(normalized.contains);
  }
}

Future<bool> detectAndroidEmulator() async {
  if (kIsWeb || !Platform.isAndroid) return false;

  var signals = const AndroidEmulatorSignals();

  // 1. /proc/cpuinfo — check for emulator markers
  try {
    signals = AndroidEmulatorSignals(
      cpuInfo: await File('/proc/cpuinfo').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 2. getprop — most reliable on modern emulators
  try {
    final result = await Process.run('getprop', ['ro.hardware']);
    signals = AndroidEmulatorSignals(hardware: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.build.characteristics']);
    signals = AndroidEmulatorSignals(
      buildCharacteristics: result.stdout as String,
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.product.model']);
    signals = AndroidEmulatorSignals(productModel: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 3. /system/build.prop — fallback file check
  try {
    signals = AndroidEmulatorSignals(
      buildProp: await File('/system/build.prop').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  return false;
}

import 'dart:typed_data';

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('RendererBackendPolicy', () {
    const policy = RendererBackendPolicy();

    test('prefers GPU on healthy target', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: false,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('uses GPU on healthy android emulator in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: false,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('falls back to CPU on android emulator when GPU health fails', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: true,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.twoD,
        ),
      );

      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
      expect(decision.reasonToken, 'gpu_health_check_failed');
    });

    test('keeps 3D modules on GPU in auto mode', () {
      final decision = policy.decide(
        const BackendPolicyInput(
          isAndroid: true,
          isWeb: false,
          isEmulator: false,
          userMode: RendererBackendMode.auto,
          gpuHealthFailed: true,
          deepZoomNeedsCpu: false,
          dimension: FractalDimension.threeD,
        ),
      );

      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });
  });

  group('Render validation', () {
    test('detects non-black histogram and progression', () {
      final frameA = Uint8List.fromList(List<int>.filled(16 * 4, 0));
      final frameB = Uint8List.fromList(List<int>.filled(16 * 4, 0));

      // center pixel (1,1) for a 4x4 image
      const center = (1 * 4 + 1) * 4;
      frameB[center] = 64;
      frameB[center + 1] = 96;
      frameB[center + 2] = 128;

      // add additional non-black + changed pixels
      for (int i = 0; i < frameB.length; i += 8) {
        frameB[i] = 32;
        frameB[i + 1] = 16;
        frameB[i + 2] = 48;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });
  });
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/features/renderer/backend_policy.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  const policy = RendererBackendPolicy();

  // Helper to build a standard 2D auto input with overrides.
  BackendPolicyInput buildInput({
    bool isAndroid = false,
    bool isWeb = false,
    bool isEmulator = false,
    RendererBackendMode userMode = RendererBackendMode.auto,
    bool gpuHealthFailed = false,
    bool deepZoomNeedsCpu = false,
    FractalDimension dimension = FractalDimension.twoD,
  }) {
    return BackendPolicyInput(
      isAndroid: isAndroid,
      isWeb: isWeb,
      isEmulator: isEmulator,
      userMode: userMode,
      gpuHealthFailed: gpuHealthFailed,
      deepZoomNeedsCpu: deepZoomNeedsCpu,
      dimension: dimension,
    );
  }

  group('cpuOnly user mode', () {
    test('cpuOnly always returns cpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.cpuOnly));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly on non-emulator non-android still returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: false,
        isEmulator: false,
        userMode: RendererBackendMode.cpuOnly,
      ));
      expect(decision.backend, RendererBackend.cpu);
    });

    test('cpuOnly with gpuHealthFailed still returns cpu via manualToggle', () {
      // cpuOnly is evaluated before health-check; reason should be manualToggle
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('cpuOnly is ignored for 3D module — GPU required', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // 3D always uses GPU; cpuOnly is overridden
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
    });
  });

  group('gpuOnly user mode', () {
    test('gpuOnly always returns gpu backend for 2D', () {
      final decision =
          policy.decide(buildInput(userMode: RendererBackendMode.gpuOnly));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses deep-zoom CPU fallback', () {
      // gpuOnly is evaluated before deepZoomNeedsCpu check
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });

    test('gpuOnly bypasses GPU health check', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.gpuOnly,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.manualToggle);
    });
  });

  group('deep zoom CPU fallback', () {
    test('deepZoomNeedsCpu triggers cpu backend in auto mode', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.deepZoomPrecision);
    });

    test('deepZoomNeedsCpu reasonToken is deep_zoom_precision', () {
      final decision = policy.decide(buildInput(deepZoomNeedsCpu: true));
      expect(decision.reasonToken, 'deep_zoom_precision');
    });

    test('deepZoomNeedsCpu is evaluated after gpuHealthFailed', () {
      // gpuHealthFailed is checked first in the policy
      final decision = policy.decide(buildInput(
        gpuHealthFailed: true,
        deepZoomNeedsCpu: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });
  });

  group('GPU health failure', () {
    test('GPU health failure in auto mode returns cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('combined emulator + GPU health fail returns cpu', () {
      final decision = policy.decide(buildInput(
        isAndroid: true,
        isEmulator: true,
        gpuHealthFailed: true,
      ));
      expect(decision.backend, RendererBackend.cpu);
      expect(decision.reasonCode, FallbackReasonCode.gpuHealthCheckFailed);
    });

    test('isFallback is true when backend is cpu', () {
      final decision = policy.decide(buildInput(gpuHealthFailed: true));
      expect(decision.isFallback, isTrue);
    });
  });

  group('policy explanation', () {
    test('exposes selected rule while preserving decide compatibility', () {
      final resolution = policy.explain(buildInput(gpuHealthFailed: true));

      expect(resolution.selectedRule, 'gpu_health_failed');
      expect(resolution.platformSignalsUsed, isFalse);
      expect(resolution.decision.backend, RendererBackend.cpu);
      expect(policy.decide(buildInput(gpuHealthFailed: true)).reasonCode,
          resolution.decision.reasonCode);
    });

    test('documents platform signals as advisory in auto mode', () {
      final emulatorResolution = policy.explain(buildInput(
        isAndroid: true,
        isEmulator: true,
      ));
      final webResolution = policy.explain(buildInput(isWeb: true));

      expect(emulatorResolution.selectedRule, 'healthy_gpu_target');
      expect(emulatorResolution.platformSignalsUsed, isFalse);
      expect(webResolution.selectedRule, 'healthy_gpu_target');
      expect(webResolution.platformSignalsUsed, isFalse);
    });
  });

  group('healthy GPU with auto mode', () {
    test('healthy GPU with auto mode returns gpu', () {
      final decision = policy.decide(buildInput());
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.none);
    });

    test('isFallback is false for gpu decision', () {
      final decision = policy.decide(buildInput());
      expect(decision.isFallback, isFalse);
    });

    test('reasonToken is none for healthy GPU', () {
      final decision = policy.decide(buildInput());
      expect(decision.reasonToken, 'none');
    });

    test('toUserStatusText returns GPU label on healthy path', () {
      final decision = policy.decide(buildInput());
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('3D module (unsupported GPU override)', () {
    test('3D module with auto mode uses GPU', () {
      final decision =
          policy.decide(buildInput(dimension: FractalDimension.threeD));
      expect(decision.backend, RendererBackend.gpu);
    });

    test('cpuOnly is ignored for 3D — moduleUnsupported reason', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.reasonCode, FallbackReasonCode.moduleUnsupported);
      expect(decision.reasonToken, 'module_unsupported');
    });

    test('3D module toUserStatusText returns GPU label (backend is gpu)', () {
      final decision = policy.decide(buildInput(
        userMode: RendererBackendMode.cpuOnly,
        dimension: FractalDimension.threeD,
      ));
      // backend == gpu so isFallback is false; toUserStatusText returns 'Renderer: GPU'
      // regardless of reasonCode because the !isFallback check fires first.
      expect(decision.backend, RendererBackend.gpu);
      expect(decision.isFallback, isFalse);
      expect(decision.toUserStatusText(), 'Renderer: GPU');
    });
  });

  group('AndroidEmulatorSignals', () {
    test('classifies each emulator marker without IO', () {
      const samples = [
        AndroidEmulatorSignals(cpuInfo: 'Hardware\t: ranchu'),
        AndroidEmulatorSignals(
            cpuInfo: 'Processor\t: Android Virtual Processor'),
        AndroidEmulatorSignals(cpuInfo: 'vendor_id\t: QEMU'),
        AndroidEmulatorSignals(hardware: ' goldfish\n'),
        AndroidEmulatorSignals(buildCharacteristics: 'nosdcard,emulator'),
        AndroidEmulatorSignals(productModel: 'sdk_gphone64_x86_64'),
        AndroidEmulatorSignals(productModel: 'Android SDK built for x86'),
        AndroidEmulatorSignals(buildProp: 'ro.hardware=ranchu\n'),
        AndroidEmulatorSignals(buildProp: 'ro.product.cpu.abi=generic_x86'),
      ];

      for (final sample in samples) {
        expect(sample.isEmulator, isTrue);
      }
    });

    test('does not classify physical-device-looking signals as emulator', () {
      const signals = AndroidEmulatorSignals(
        cpuInfo: 'Hardware\t: Qualcomm Technologies',
        hardware: 'qcom',
        buildCharacteristics: 'default',
        productModel: 'Pixel 8',
        buildProp: 'ro.hardware=qcom\nro.product.model=Pixel 8\n',
      );

      expect(signals.isEmulator, isFalse);
    });
  });

  group('BackendDecision helpers', () {
    test('toLogLine contains backend, reason, module, and detail', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: 'deep_zoom_precision_policy',
      );
      final line = decision.toLogLine(moduleId: 'mandelbrot');
      expect(line, contains('backend=cpu'));
      expect(line, contains('reason=deep_zoom_precision'));
      expect(line, contains('module=mandelbrot'));
      expect(line, contains('detail=deep_zoom_precision_policy'));
    });

    test('toUserStatusText for deep zoom precision', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.deepZoomPrecision,
        detail: '',
      );
      expect(decision.toUserStatusText(), 'Deep zoom precision mode enabled');
    });

    test('toUserStatusText for manual toggle cpu', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.manualToggle,
        detail: 'cpu_only',
      );
      expect(decision.toUserStatusText(), 'Renderer preference applied');
    });

    test('toUserStatusText for forced by flag', () {
      const decision = BackendDecision(
        backend: RendererBackend.cpu,
        reasonCode: FallbackReasonCode.forcedByFlag,
        detail: '',
      );
      expect(
          decision.toUserStatusText(), 'Stable renderer forced by launch flag');
    });
  });
}

import 'dart:math' as math;
import 'dart:typed_data';

const int _rgbaStride = 4;

/// Numeric thresholds used by render-health probes.
///
/// Keeping these cutoffs in one value object makes the pass/fail contract
/// replayable from tests instead of scattering magic constants through the
/// frame and pair validators.
class RenderValidationThresholds {
  final int blackThreshold;
  final int differenceThreshold;
  final double minimumNonBlackRatio;
  final double minimumProgressionRatio;
  final double minimumIterationDeltaRatio;

  static const defaults = RenderValidationThresholds();

  const RenderValidationThresholds({
    this.blackThreshold = 8,
    this.differenceThreshold = 12,
    this.minimumNonBlackRatio = 0.01,
    this.minimumProgressionRatio = 0.002,
    this.minimumIterationDeltaRatio = 0.01,
  })  : assert(blackThreshold >= 0),
        assert(differenceThreshold >= 0),
        assert(minimumNonBlackRatio >= 0.0),
        assert(minimumProgressionRatio >= 0.0),
        assert(minimumIterationDeltaRatio >= 0.0);

  bool isNonBlackPixel(int r, int g, int b) =>
      r > blackThreshold || g > blackThreshold || b > blackThreshold;

  bool isVisiblyDifferent({
    required int rA,
    required int gA,
    required int bA,
    required int rB,
    required int gB,
    required int bB,
  }) {
    final dr = (rB - rA).abs();
    final dg = (gB - gA).abs();
    final db = (bB - bA).abs();
    return dr + dg + db > differenceThreshold;
  }

  bool histogramSaneFor(double nonBlackRatio) =>
      nonBlackRatio > minimumNonBlackRatio;

  bool frameProgressedFor(double progressionRatio) =>
      progressionRatio > minimumProgressionRatio;

  bool iterationDeltaVisibleFor(double progressionRatio) =>
      progressionRatio > minimumIterationDeltaRatio;
}

class _RenderFrameGeometry {
  final int width;
  final int height;
  final int totalPixels;
  final int centerIndex;

  const _RenderFrameGeometry._({
    required this.width,
    required this.height,
    required this.totalPixels,
    required this.centerIndex,
  });

  factory _RenderFrameGeometry({required int width, required int height}) {
    if (width <= 0 || height <= 0) {
      return _RenderFrameGeometry._(
        width: width,
        height: height,
        totalPixels: 0,
        centerIndex: -1,
      );
    }

    final totalPixels = width * height;
    final cx = (width / 2).floor();
    final cy = (height / 2).floor();
    return _RenderFrameGeometry._(
      width: width,
      height: height,
      totalPixels: totalPixels,
      centerIndex: (cy * width + cx) * _rgbaStride,
    );
  }

  bool canReadCenter(Uint8List frame) =>
      centerIndex >= 0 && centerIndex + 2 < frame.length;

  int readablePixelCount(Uint8List frame) =>
      math.min(totalPixels, frame.length ~/ _rgbaStride);

  bool hasCompleteFrame(Uint8List frame) =>
      totalPixels > 0 && readablePixelCount(frame) == totalPixels;
}

bool _isNonBlack(Uint8List frame, int index) =>
    RenderValidationThresholds.defaults.isNonBlackPixel(
      frame[index],
      frame[index + 1],
      frame[index + 2],
    );

bool _isVisiblyDifferent(Uint8List frameA, Uint8List frameB, int index) =>
    RenderValidationThresholds.defaults.isVisiblyDifferent(
      rA: frameA[index],
      gA: frameA[index + 1],
      bA: frameA[index + 2],
      rB: frameB[index],
      gB: frameB[index + 1],
      bB: frameB[index + 2],
    );

int _countNonBlackPixels(Uint8List frame, int readablePixels) {
  int nonBlack = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isNonBlack(frame, i)) {
      nonBlack++;
    }
  }
  return nonBlack;
}

int _countDifferentPixels({
  required Uint8List frameA,
  required Uint8List frameB,
  required int readablePixels,
}) {
  int different = 0;
  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isVisiblyDifferent(frameA, frameB, i)) {
      different++;
    }
  }
  return different;
}

/// Replayable center-pixel read used by render validation.
///
/// Center sampling is shared by single-frame and pair validators. Exposing the
/// read separately makes the odd/even center convention and truncated-frame
/// fallback replayable without inferring it from final pass/fail booleans.
class RenderCenterSample {
  final int r;
  final int g;
  final int b;
  final bool readable;
  final bool nonBlack;

  const RenderCenterSample({
    required this.r,
    required this.g,
    required this.b,
    required this.readable,
    required this.nonBlack,
  });

  const RenderCenterSample.unreadable()
      : r = 0,
        g = 0,
        b = 0,
        readable = false,
        nonBlack = false;
}

/// Replayable counters used by frame validation.
///
/// This separates byte-buffer sampling from threshold decisions so truncated
/// frames and invalid dimensions can be characterized without inferring hidden
/// state from the final pass/fail booleans.
class RenderFrameSample {
  final int totalPixels;
  final int readablePixels;
  final int nonBlackPixels;
  final bool centerReadable;

  const RenderFrameSample({
    required this.totalPixels,
    required this.readablePixels,
    required this.nonBlackPixels,
    required this.centerReadable,
  });

  bool get hasCompleteFrame => totalPixels > 0 && readablePixels == totalPixels;

  double get nonBlackRatio =>
      totalPixels == 0 ? 0.0 : nonBlackPixels / totalPixels;
}

/// Replayable counters used by pair validation.
class RenderPairSample {
  final RenderFrameSample frameB;
  final int comparablePixels;
  final int differentPixels;
  final bool hasCompletePair;

  const RenderPairSample({
    required this.frameB,
    required this.comparablePixels,
    required this.differentPixels,
    required this.hasCompletePair,
  });

  double get progressionRatio => frameB.totalPixels == 0 || !hasCompletePair
      ? 0.0
      : differentPixels / frameB.totalPixels;
}

class RenderFrameStats {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;

  const RenderFrameStats({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
  });

  String summary(String backend) {
    return '[renderer] render_frame_stats backend=$backend center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} histogram_sane=$histogramSane';
  }
}

RenderFrameSample sampleRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final readablePixels = geometry.readablePixelCount(frame);
  return RenderFrameSample(
    totalPixels: geometry.totalPixels,
    readablePixels: readablePixels,
    nonBlackPixels: _countNonBlackPixels(frame, readablePixels),
    centerReadable: geometry.canReadCenter(frame),
  );
}

RenderCenterSample sampleRenderCenter({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  if (!geometry.canReadCenter(frame)) {
    return const RenderCenterSample.unreadable();
  }

  final cIndex = geometry.centerIndex;
  return RenderCenterSample(
    r: frame[cIndex],
    g: frame[cIndex + 1],
    b: frame[cIndex + 2],
    readable: true,
    nonBlack: _isNonBlack(frame, cIndex),
  );
}

RenderFrameStats validateRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final sample = sampleRenderFrame(frame: frame, width: width, height: height);
  final center = sampleRenderCenter(
    frame: frame,
    width: width,
    height: height,
  );

  final nonBlackRatio = sample.nonBlackRatio;
  final histogramSane =
      RenderValidationThresholds.defaults.histogramSaneFor(nonBlackRatio);

  return RenderFrameStats(
    centerR: center.r,
    centerG: center.g,
    centerB: center.b,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: center.nonBlack,
    histogramSane: histogramSane,
  );
}

class RenderCheckResult {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;
  final bool frameProgressed;
  final bool iterationDeltaVisible;

  const RenderCheckResult({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
    required this.frameProgressed,
    required this.iterationDeltaVisible,
  });

  bool get pass =>
      centerNonBlack &&
      histogramSane &&
      frameProgressed &&
      iterationDeltaVisible;

  String summary(String backend) {
    return '[renderer] render_check backend=$backend pass=$pass center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} frame_progressed=$frameProgressed iter_delta=$iterationDeltaVisible';
  }
}

RenderPairSample sampleRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final frameBSample = sampleRenderFrame(
    frame: frameB,
    width: width,
    height: height,
  );
  final comparablePixels = math.min(
    geometry.readablePixelCount(frameA),
    frameBSample.readablePixels,
  );
  return RenderPairSample(
    frameB: frameBSample,
    comparablePixels: comparablePixels,
    differentPixels: _countDifferentPixels(
      frameA: frameA,
      frameB: frameB,
      readablePixels: comparablePixels,
    ),
    hasCompletePair:
        geometry.hasCompleteFrame(frameA) && geometry.hasCompleteFrame(frameB),
  );
}

RenderCheckResult validateRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final sample = sampleRenderPair(
    frameA: frameA,
    frameB: frameB,
    width: width,
    height: height,
  );
  final center = sampleRenderCenter(
    frame: frameB,
    width: width,
    height: height,
  );

  final nonBlackRatio = sample.frameB.nonBlackRatio;
  final histogramSane =
      RenderValidationThresholds.defaults.histogramSaneFor(nonBlackRatio);
  // Progression is a whole-frame claim; a truncated frame can still prove the
  // current histogram, but cannot prove frame-to-frame movement.
  final progressionRatio = sample.progressionRatio;
  final frameProgressed =
      RenderValidationThresholds.defaults.frameProgressedFor(progressionRatio);
  final iterationDeltaVisible = RenderValidationThresholds.defaults
      .iterationDeltaVisibleFor(progressionRatio);

  return RenderCheckResult(
    centerR: center.r,
    centerG: center.g,
    centerB: center.b,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: center.nonBlack,
    histogramSane: histogramSane,
    frameProgressed: frameProgressed,
    iterationDeltaVisible: iterationDeltaVisible,
  );
}

import 'dart:typed_data';
import 'dart:math' as math;

/// Result of convergence detection analysis.
class ConvergenceChangeRatio {
  static const double equalityTolerance = 1e-9;

  const ConvergenceChangeRatio._();

  static bool approximatelyEqual(double a, double b) =>
      (a - b).abs() < equalityTolerance;
}

class ConvergenceResult {
  /// Whether the image has converged (stabilized).
  final bool converged;

  /// The ratio of pixels that changed between frames (0.0 to 1.0).
  final double changeRatio;

  /// Suggested number of iterations for the next render.
  final int suggestedIterations;

  const ConvergenceResult({
    required this.converged,
    required this.changeRatio,
    required this.suggestedIterations,
  });

  @override
  String toString() {
    return 'ConvergenceResult(converged: $converged, '
        'changeRatio: ${changeRatio.toStringAsFixed(6)}, '
        'suggestedIterations: $suggestedIterations)';
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is ConvergenceResult &&
        other.converged == converged &&
        ConvergenceChangeRatio.approximatelyEqual(
          other.changeRatio,
          changeRatio,
        ) &&
        other.suggestedIterations == suggestedIterations;
  }

  @override
  int get hashCode => Object.hash(converged, suggestedIterations);
}

/// Replayable frame shape contract for convergence comparison.
class ConvergenceFrameSpec {
  final int width;
  final int height;

  const ConvergenceFrameSpec({
    required this.width,
    required this.height,
  });

  int get expectedRgbaLength => width * height * 4;

  void validateBuffers({
    required Uint8List previous,
    required Uint8List current,
  }) {
    if (width <= 0 || height <= 0) {
      throw ArgumentError('Invalid dimensions: ${width}x$height');
    }

    if (previous.length != current.length) {
      throw ArgumentError(
        'Buffer size mismatch: previous=${previous.length}, current=${current.length}',
      );
    }

    if (previous.length != expectedRgbaLength) {
      throw ArgumentError(
        'Buffer size mismatch: expected=$expectedRgbaLength (${width}x$height RGBA), '
        'got=${previous.length}',
      );
    }
  }
}

/// Replayable downsampling grid for convergence comparison.
class ConvergenceSamplingPlan {
  /// Integer stride used to sample the original frame.
  final int factor;

  /// Width of the sampled comparison grid.
  final int sampledWidth;

  /// Height of the sampled comparison grid.
  final int sampledHeight;

  const ConvergenceSamplingPlan._({
    required this.factor,
    required this.sampledWidth,
    required this.sampledHeight,
  });

  factory ConvergenceSamplingPlan({
    required int width,
    required int height,
    required int target,
  }) {
    if (width <= 0 || height <= 0) {
      throw ArgumentError('Invalid dimensions: ${width}x$height');
    }
    if (target <= 0) {
      throw ArgumentError('Invalid downsampleTarget: $target');
    }

    final maxDimension = math.max(width, height);
    final factor = math.max(1, (maxDimension / target).ceil());
    return ConvergenceSamplingPlan._(
      factor: factor,
      sampledWidth: (width / factor).ceil(),
      sampledHeight: (height / factor).ceil(),
    );
  }
}

/// Replayable threshold contract for RGB pixel-change comparison.
class ConvergencePixelChangeRule {
  final int threshold;

  const ConvergencePixelChangeRule(this.threshold);

  void validate() {
    if (threshold < 0) {
      throw ArgumentError('Invalid pixelDifferenceThreshold: $threshold');
    }
  }

  bool sampleChanged({
    required Uint8List previous,
    required Uint8List current,
    required int pixelIndex,
  }) {
    for (int channel = 0; channel < 3; channel++) {
      final diff =
          (previous[pixelIndex + channel] - current[pixelIndex + channel])
              .abs();
      if (diff > threshold) return true;
    }
    return false;
  }
}

/// Replayable count summary for one convergence comparison.
class ConvergenceComparisonStats {
  final int changedPixels;
  final int totalPixels;

  const ConvergenceComparisonStats({
    required this.changedPixels,
    required this.totalPixels,
  })  : assert(changedPixels >= 0, 'changedPixels must be non-negative'),
        assert(totalPixels >= 0, 'totalPixels must be non-negative'),
        assert(
          changedPixels <= totalPixels,
          'changedPixels must not exceed totalPixels',
        );

  double get changeRatio => totalPixels > 0 ? changedPixels / totalPixels : 0.0;
}

/// Replayable iteration recommendation for convergence results.
class ConvergenceIterationRecommendation {
  const ConvergenceIterationRecommendation._();

  static int forChangeRatio({
    required double changeRatio,
    required int currentIterations,
  }) {
    if (currentIterations <= 0) {
      throw ArgumentError('Invalid currentIterations: $currentIterations');
    }

    if (changeRatio > ConvergenceDetector.changeThreshold) {
      return (currentIterations * ConvergenceDetector.iterationMultiplier)
          .round();
    }
    return currentIterations;
  }
}

/// Detects convergence between two rendered frames to enable adaptive iteration refinement.
///
/// Compares two RGBA frame buffers and determines if the rendering has stabilized.
/// Uses downsampling to ~64x64 resolution for performance.
class ConvergenceDetector {
  /// Threshold for considering a pixel as "changed" (per channel, 0-255).
  final int pixelDifferenceThreshold;

  /// Target downsample resolution for comparison (approximate).
  final int downsampleTarget;

  /// Convergence threshold: below this ratio, the image is considered converged.
  static const double convergenceThreshold = 0.001;

  /// Change threshold: above this ratio, suggest increasing iterations.
  static const double changeThreshold = 0.01;

  /// Multiplier for suggested iterations when image hasn't converged.
  static const double iterationMultiplier = 1.5;

  const ConvergenceDetector({
    this.pixelDifferenceThreshold = 5,
    this.downsampleTarget = 64,
  });

  /// Compares two RGBA frame buffers and returns convergence analysis.
  ///
  /// [previous] and [current] must be RGBA Uint8List buffers of identical dimensions.
  /// [width] and [height] are the original buffer dimensions in pixels.
  /// [currentIterations] is the iteration count used to render [current].
  ///
  /// Returns a [ConvergenceResult] indicating whether the image has converged,
  /// the change ratio, and suggested iterations for the next render.
  ConvergenceResult detect({
    required Uint8List previous,
    required Uint8List current,
    required int width,
    required int height,
    required int currentIterations,
  }) {
    ConvergenceFrameSpec(width: width, height: height).validateBuffers(
      previous: previous,
      current: current,
    );
    if (currentIterations <= 0) {
      throw ArgumentError('Invalid currentIterations: $currentIterations');
    }

    final stats = compareFrames(
      previous: previous,
      current: current,
      width: width,
      height: height,
    );
    final changeRatio = stats.changeRatio;

    return ConvergenceResult(
      converged: changeRatio < convergenceThreshold,
      changeRatio: changeRatio,
      suggestedIterations: ConvergenceIterationRecommendation.forChangeRatio(
        changeRatio: changeRatio,
        currentIterations: currentIterations,
      ),
    );
  }

  /// Returns replayable comparison counts before policy thresholds are applied.
  ConvergenceComparisonStats compareFrames({
    required Uint8List previous,
    required Uint8List current,
    required int width,
    required int height,
  }) {
    final frameSpec = ConvergenceFrameSpec(width: width, height: height);
    frameSpec.validateBuffers(previous: previous, current: current);

    final pixelChangeRule = ConvergencePixelChangeRule(
      pixelDifferenceThreshold,
    );
    pixelChangeRule.validate();

    final samplingPlan = ConvergenceSamplingPlan(
      width: width,
      height: height,
      target: downsampleTarget,
    );

    int changedPixels = 0;
    int totalPixels = 0;

    for (int y = 0; y < samplingPlan.sampledHeight; y++) {
      for (int x = 0; x < samplingPlan.sampledWidth; x++) {
        final srcX = (x * samplingPlan.factor).clamp(0, width - 1);
        final srcY = (y * samplingPlan.factor).clamp(0, height - 1);
        final pixelIndex = (srcY * width + srcX) * 4;

        if (pixelChangeRule.sampleChanged(
          previous: previous,
          current: current,
          pixelIndex: pixelIndex,
        )) {
          changedPixels++;
        }
        totalPixels++;
      }
    }

    return ConvergenceComparisonStats(
      changedPixels: changedPixels,
      totalPixels: totalPixels,
    );
  }
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

/// Builds a Uint8List RGBA frame of [w]x[h] pixels, all zeroed (black).
Uint8List _blackFrame(int w, int h) => Uint8List(w * h * 4);

/// Pixel index for (x, y) in a [w]-wide RGBA frame.
int _px(int x, int y, int w) => (y * w + x) * 4;

void main() {
  group('RenderValidationThresholds', () {
    test('exposes default health thresholds as replayable comparisons', () {
      const thresholds = RenderValidationThresholds.defaults;

      expect(thresholds.blackThreshold, 8);
      expect(thresholds.differenceThreshold, 12);
      expect(thresholds.minimumNonBlackRatio, 0.01);
      expect(thresholds.minimumProgressionRatio, 0.002);
      expect(thresholds.minimumIterationDeltaRatio, 0.01);

      expect(thresholds.isNonBlackPixel(8, 8, 8), isFalse);
      expect(thresholds.isNonBlackPixel(9, 0, 0), isTrue);
      expect(
        thresholds.isVisiblyDifferent(
          rA: 0,
          gA: 0,
          bA: 0,
          rB: 4,
          gB: 4,
          bB: 4,
        ),
        isFalse,
      );
      expect(
        thresholds.isVisiblyDifferent(
          rA: 0,
          gA: 0,
          bA: 0,
          rB: 5,
          gB: 4,
          bB: 4,
        ),
        isTrue,
      );
      expect(thresholds.histogramSaneFor(0.01), isFalse);
      expect(thresholds.histogramSaneFor(0.0101), isTrue);
      expect(thresholds.frameProgressedFor(0.002), isFalse);
      expect(thresholds.frameProgressedFor(0.0021), isTrue);
      expect(thresholds.iterationDeltaVisibleFor(0.01), isFalse);
      expect(thresholds.iterationDeltaVisibleFor(0.0101), isTrue);
    });
  });

  group('sampleRenderCenter', () {
    test('exposes even-dimension center sampling and black fallback', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 120;
      frame[idx + 2] = 140;

      final center = sampleRenderCenter(frame: frame, width: 4, height: 4);
      final truncatedCenter = sampleRenderCenter(
        frame: Uint8List(4),
        width: 4,
        height: 4,
      );

      expect(center.readable, isTrue);
      expect(center.r, 100);
      expect(center.g, 120);
      expect(center.b, 140);
      expect(center.nonBlack, isTrue);
      expect(truncatedCenter.readable, isFalse);
      expect(truncatedCenter.r, 0);
      expect(truncatedCenter.g, 0);
      expect(truncatedCenter.b, 0);
      expect(truncatedCenter.nonBlack, isFalse);
    });
  });

  group('sampleRenderFrame', () {
    test('exposes readable pixel counts for truncated frames', () {
      final frame = _blackFrame(3, 1);
      frame[0] = 80;
      frame[4] = 80;

      final sample = sampleRenderFrame(frame: frame, width: 4, height: 2);

      expect(sample.totalPixels, 8);
      expect(sample.readablePixels, 3);
      expect(sample.nonBlackPixels, 2);
      expect(sample.centerReadable, isFalse);
      expect(sample.hasCompleteFrame, isFalse);
      expect(sample.nonBlackRatio, 2 / 8);
    });
  });

  group('sampleRenderPair', () {
    test('exposes comparable pixels and gates progression on complete pairs',
        () {
      final frameA = _blackFrame(2, 1);
      final frameB = _blackFrame(3, 1);
      frameB[0] = 80;
      frameB[4] = 80;
      frameB[8] = 80;

      final sample = sampleRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 3,
        height: 1,
      );

      expect(sample.frameB.totalPixels, 3);
      expect(sample.frameB.readablePixels, 3);
      expect(sample.comparablePixels, 2);
      expect(sample.differentPixels, 2);
      expect(sample.hasCompletePair, isFalse);
      expect(sample.progressionRatio, 0.0);
    });
  });

  group('validateRenderFrame', () {
    test('empty dimensions return invalid black stats instead of crashing', () {
      final stats = validateRenderFrame(
        frame: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('negative dimensions are treated as invalid frame geometry', () {
      final frame = _blackFrame(1, 1);
      frame[0] = 80;
      frame[1] = 80;
      frame[2] = 80;

      final stats = validateRenderFrame(
        frame: frame,
        width: -1,
        height: -1,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects all-black frame', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects non-black center pixel', () {
      final frame = _blackFrame(4, 4);
      // center of 4x4 is floor(2), floor(2) = (2,2)
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 150;
      frame[idx + 2] = 200;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 100);
      expect(stats.centerG, 150);
      expect(stats.centerB, 200);
      expect(stats.centerNonBlack, isTrue);
    });

    test('calculates correct nonBlackRatio', () {
      // 8 pixels total; make exactly 4 non-black
      final frame = _blackFrame(4, 2);
      // pixels at (0,0),(1,0),(2,0),(3,0) — first row, r=20 > 8 threshold
      for (int col = 0; col < 4; col++) {
        frame[_px(col, 0, 4)] = 20;
      }
      final stats = validateRenderFrame(frame: frame, width: 4, height: 2);

      expect(stats.nonBlackRatio, closeTo(4 / 8, 1e-9));
    });

    test('histogramSane is false when ratio <= 0.01', () {
      // 100 pixels, only 1 non-black => ratio = 0.01 which is NOT > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.01, 1e-9));
      expect(stats.histogramSane, isFalse);
    });

    test('histogramSane is true when ratio > 0.01', () {
      // 100 pixels, 2 non-black => ratio = 0.02 > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      frame[4] = 20; // next pixel (x=1,y=0)
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.02, 1e-9));
      expect(stats.histogramSane, isTrue);
    });

    test('summary includes backend name', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      final summary = stats.summary('gpu');

      expect(summary, contains('backend=gpu'));
      expect(summary, contains('[renderer]'));
      expect(summary, contains('non_black_ratio='));
      expect(summary, contains('histogram_sane='));
    });

    test('boundary: threshold pixel value of 8 is still counted as black', () {
      final frame = _blackFrame(4, 4);
      // Set center pixel RGB all to exactly 8 — threshold is > 8, so this is black
      final idx = _px(2, 2, 4);
      frame[idx] = 8;
      frame[idx + 1] = 8;
      frame[idx + 2] = 8;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isFalse);
    });

    test('boundary: pixel value of 9 is counted as non-black', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 9;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isTrue);
    });
  });

  group('validateRenderPair', () {
    test('empty dimensions return failed check instead of crashing', () {
      final result = validateRenderPair(
        frameA: Uint8List(0),
        frameB: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('negative dimensions cannot pass from readable single-pixel frames',
        () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(1, 1);
      frameB[0] = 80;
      frameB[1] = 80;
      frameB[2] = 80;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: -1,
        height: -1,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.nonBlackRatio, 0.0);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('detects frame progression when enough pixels differ', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);

      // Make every pixel differ significantly (dr+dg+db > 12)
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 50;
        frameB[i + 1] = 50;
        frameB[i + 2] = 50;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });

    test('frameProgressed is false when frames are identical', () {
      final frameA = _blackFrame(4, 4);
      final frameB = Uint8List.fromList(frameA);

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('iterationDeltaVisible requires > 1% different pixels', () {
      // 100 pixels total; need > 1 different pixel for iterationDeltaVisible
      // Exactly 1 different pixel => 1% which is NOT > 0.01
      final frameA = _blackFrame(10, 10);
      final frameB = Uint8List.fromList(frameA);
      frameB[0] = 100;
      frameB[1] = 100;
      frameB[2] = 100;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      // progressionRatio = 1/100 = 0.01; frameProgressed needs > 0.002 (true)
      expect(result.frameProgressed, isTrue);
      // iterationDeltaVisible needs > 0.01 (false — exactly 0.01)
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('uses frameB readable pixels for histogram when frameA is truncated',
        () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(10, 10);

      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.nonBlackRatio, 1.0);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('does not report progression from incomplete frame pairs', () {
      final frameA = _blackFrame(1, 1);
      final frameB = _blackFrame(1, 1);
      frameB[0] = 80;
      frameB[1] = 80;
      frameB[2] = 80;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('pass is true only when all checks pass', () {
      // Build a 10x10 frame where enough pixels are non-black and different
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Fill all pixels in frameB with colour that exceeds all thresholds
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
        frameB[i + 3] = 255;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
      expect(result.pass, isTrue);
    });

    test('pass is false when centerNonBlack is false', () {
      // Non-zero progression but center stays black
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Colour many pixels except the center (5,5)
      for (int row = 0; row < 10; row++) {
        for (int col = 0; col < 10; col++) {
          if (row == 5 && col == 5) continue;
          final i = _px(col, row, 10);
          frameB[i] = 80;
          frameB[i + 1] = 80;
          frameB[i + 2] = 80;
        }
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isFalse);
      expect(result.pass, isFalse);
    });

    test('handles all-identical frames — no progression', () {
      final frameA = Uint8List.fromList(List.filled(20 * 20 * 4, 50));
      final frameB = Uint8List.fromList(List.filled(20 * 20 * 4, 50));

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 20,
        height: 20,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('summary includes pass status and backend name', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);
      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );
      final summary = result.summary('cpu');

      expect(summary, contains('backend=cpu'));
      expect(summary, contains('pass='));
      expect(summary, contains('[renderer]'));
    });
  });
}

import 'dart:typed_data';
import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/convergence_detector.dart';

void main() {
  group('ConvergenceResult', () {
    test('hashCode is compatible with approximate changeRatio equality', () {
      const base = ConvergenceResult(
        converged: true,
        changeRatio: 0.123456789,
        suggestedIterations: 100,
      );
      const approximatelyEqual = ConvergenceResult(
        converged: true,
        changeRatio: 0.1234567895,
        suggestedIterations: 100,
      );

      expect(base, approximatelyEqual);
      expect(base.hashCode, approximatelyEqual.hashCode);
      expect({base}, contains(approximatelyEqual));
    });
  });

  group('ConvergenceComparisonStats', () {
    test('exposes replayable change ratio from sampled counts', () {
      const stats = ConvergenceComparisonStats(
        changedPixels: 2,
        totalPixels: 8,
      );

      expect(stats.changeRatio, 0.25);
    });
  });

  group('ConvergenceIterationRecommendation', () {
    test('keeps iterations for minor changes and rejects invalid counts', () {
      expect(
        ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: ConvergenceDetector.changeThreshold,
          currentIterations: 100,
        ),
        100,
      );
      expect(
        () => ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: 0.0,
          currentIterations: 0,
        ),
        throwsArgumentError,
      );
    });

    test('increases iterations above the significant-change threshold', () {
      expect(
        ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: ConvergenceDetector.changeThreshold + 0.001,
          currentIterations: 100,
        ),
        150,
      );
    });
  });

  group('ConvergenceSamplingPlan', () {
    test('keeps sampling grid dimensions replayable for non-square frames', () {
      final plan = ConvergenceSamplingPlan(width: 130, height: 65, target: 64);

      expect(plan.factor, 3);
      expect(plan.sampledWidth, 44);
      expect(plan.sampledHeight, 22);
    });

    test('rejects invalid downsample target before comparing frames', () {
      expect(
        () => ConvergenceSamplingPlan(width: 64, height: 64, target: 0),
        throwsArgumentError,
      );
    });
  });

  group('ConvergenceDetector', () {
    const detector = ConvergenceDetector();

    test('compareFrames exposes sampled counts before convergence policy', () {
      final previous = Uint8List(4 * 4 * 4);
      final current = Uint8List.fromList(previous);
      current[0] = 10;
      current[(3 * 4 + 3) * 4] = 10;

      final stats = detector.compareFrames(
        previous: previous,
        current: current,
        width: 4,
        height: 4,
      );

      expect(stats.changedPixels, 2);
      expect(stats.totalPixels, 16);
      expect(stats.changeRatio, 0.125);
    });

    test('compareFrames ignores alpha-only changes', () {
      final previous = Uint8List(4 * 4 * 4);
      final current = Uint8List.fromList(previous);
      current[3] = 255;

      final stats = detector.compareFrames(
        previous: previous,
        current: current,
        width: 4,
        height: 4,
      );

      expect(stats.changedPixels, 0);
      expect(stats.changeRatio, 0.0);
    });

    test('detects identical frames as converged', () {
      final buffer =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => i % 256));

      final result = detector.detect(
        previous: buffer,
        current: buffer,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      expect(result.converged, isTrue);
      expect(result.changeRatio, closeTo(0.0, 0.001));
    });

    test('detects different frames as not converged', () {
      // Need to change by more than threshold (5) per channel.
      final previous =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => i % 256));
      final current =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => (i + 10) % 256));

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // With 100% pixel change, definitely not converged.
      expect(result.converged, isFalse);
      expect(result.changeRatio, greaterThan(0.5));
    });

    test('suggests increased iterations for significantly changed frames', () {
      // Create 5% pixel change (above 1% threshold).
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List.fromList(previous);
      for (int i = 0; i < 64 * 64 * 4; i += 20) {
        current[i] = (current[i] + 10) % 256;
      }

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // 5% change > 1% threshold should suggest more iterations.
      expect(result.suggestedIterations, greaterThan(100));
    });

    test('throws domain error for invalid downsample target', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(64 * 64 * 4);
      const invalidDetector = ConvergenceDetector(downsampleTarget: 0);

      expect(
        () => invalidDetector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('throws domain error for negative pixel difference threshold', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(64 * 64 * 4);
      const invalidDetector = ConvergenceDetector(pixelDifferenceThreshold: -1);

      expect(
        () => invalidDetector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('throws on buffer size mismatch', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(32 * 32 * 4);

      expect(
        () => detector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('handles small change ratios below convergence threshold', () {
      // The convergence threshold is 0.1% - change fewer than that.
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List.fromList(previous);
      // Change only 0.05% of pixels.
      for (int i = 0; i < 64 * 64 * 4; i += 2000) {
        current[i] = (current[i] + 10) % 256;
      }

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // Very small changes (0.05%) should be below 0.1% threshold.
      expect(result.changeRatio, lessThan(0.005));
    });
  });
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x) from the public `juliaX` URL alias.
  final double? juliaX;

  /// Julia set imaginary constant (c.y) from the public `juliaY` URL alias.
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    _DeepLinkJuliaConstantParams.addRuntimeParams(
      params,
      real: juliaX,
      imaginary: juliaY,
    );

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
enum _DeepLinkRouteKind {
  customSchemeView,
  universalLinkView,
  rejected,
}

/// Shared view-route path contract for custom-scheme and universal links.
class _DeepLinkViewRoutePath {
  static const String pathOnlyView = DeepLinkService.host;
  static const String absoluteView = '/${DeepLinkService.host}';

  const _DeepLinkViewRoutePath._();

  /// A URI path that addresses the view route itself, with or without the
  /// canonical trailing slash some universal-link providers append.
  static bool isAbsoluteViewPath(String path) {
    return path == absoluteView || path == '$absoluteView/';
  }

  static bool isAuthorityRoot(String path) {
    return path.isEmpty || path == '/';
  }

  static bool isPathOnlyCustomSchemeView(String path) {
    return path == pathOnlyView || isAbsoluteViewPath(path);
  }
}

/// Normalized custom-scheme route shape.
///
/// `fractalforge://view?...` uses `view` as URI authority/host, while
/// `fractalforge:/view?...` and `fractalforge:view?...` are path-only forms.
/// Keep those shapes distinct so a non-view authority cannot smuggle a view
/// route through its path (for example `fractalforge://other/view?...`).
class _DeepLinkCustomRouteShape {
  final String host;
  final String path;

  const _DeepLinkCustomRouteShape({
    required this.host,
    required this.path,
  });

  factory _DeepLinkCustomRouteShape.fromUri(Uri uri) {
    return _DeepLinkCustomRouteShape(host: uri.host, path: uri.path);
  }

  bool get hasAuthority => host.isNotEmpty;

  bool get isViewRoute {
    if (hasAuthority) {
      return host == DeepLinkService.host &&
          _DeepLinkViewRoutePath.isAuthorityRoot(path);
    }
    return _DeepLinkViewRoutePath.isPathOnlyCustomSchemeView(path);
  }
}

class _DeepLinkRoute {
  static const allowedWebHosts = {'fractalforge.app', 'www.fractalforge.app'};

  final _DeepLinkRouteKind kind;

  const _DeepLinkRoute._(this.kind);

  bool get isAccepted => kind != _DeepLinkRouteKind.rejected;

  factory _DeepLinkRoute.fromUri(Uri uri) {
    if (uri.scheme == DeepLinkService.scheme) {
      return _DeepLinkRoute._(
        _isCustomViewRoute(uri)
            ? _DeepLinkRouteKind.customSchemeView
            : _DeepLinkRouteKind.rejected,
      );
    }

    if (uri.scheme == 'https' && allowedWebHosts.contains(uri.host)) {
      return _DeepLinkRoute._(
        _isWebViewRoute(uri)
            ? _DeepLinkRouteKind.universalLinkView
            : _DeepLinkRouteKind.rejected,
      );
    }

    return const _DeepLinkRoute._(_DeepLinkRouteKind.rejected);
  }

  static bool _isCustomViewRoute(Uri uri) {
    return _DeepLinkCustomRouteShape.fromUri(uri).isViewRoute;
  }

  static bool _isWebViewRoute(Uri uri) {
    return _DeepLinkViewRoutePath.isAbsoluteViewPath(uri.path);
  }
}

class _DeepLinkModuleId {
  static final RegExp _safePattern = RegExp(r'^[a-z0-9_]+$');

  const _DeepLinkModuleId._();

  static bool isSafe(String moduleId) => _safePattern.hasMatch(moduleId);

  static String requireSafeForBuild(String moduleId) {
    if (!isSafe(moduleId)) {
      throw ArgumentError.value(
        moduleId,
        'moduleId',
        'Deep-link module IDs must match ${_safePattern.pattern}',
      );
    }
    return moduleId;
  }
}

class _DeepLinkQuery {
  static final recognizedNames = {
    'type',
    for (final param in DeepLinkService._allQueryParams) param.name,
  };

  final Map<String, String> _params;

  const _DeepLinkQuery._(this._params);

  factory _DeepLinkQuery.fromUri(Uri uri) {
    final duplicatedRecognizedKeys = uri.queryParametersAll.entries.where(
      (entry) => recognizedNames.contains(entry.key) && entry.value.length > 1,
    );
    if (duplicatedRecognizedKeys.isNotEmpty) {
      throw FormatException(
        'Duplicate deep-link query parameter: '
        '${duplicatedRecognizedKeys.first.key}',
      );
    }

    return _DeepLinkQuery._(uri.queryParameters);
  }

  String? operator [](String name) => _params[name];
}

abstract interface class _DeepLinkQueryParamContract {
  String get name;
}

class _BoundedDoubleQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final double min;
  final double max;

  const _BoundedDoubleQueryParam(this.name, this.min, this.max);

  double? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedDouble(query[name], min, max, name);
  }

  String? format(
    Object? value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final parsed = DeepLinkService._tryFiniteDouble(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return DeepLinkService._formatDouble(
      parsed,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
  }

  bool _contains(double value) => value >= min && value <= max;
}

class _BoundedIntQueryParam implements _DeepLinkQueryParamContract {
  @override
  final String name;
  final int min;
  final int max;

  const _BoundedIntQueryParam(this.name, this.min, this.max);

  int? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedInt(query[name], min, max, name);
  }

  String? format(Object? value) {
    final parsed = _DeepLinkIntegerValue.tryParse(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return parsed.toString();
  }

  bool _contains(int value) => value >= min && value <= max;
}

class _DeepLinkIntegerValue {
  static const double _maxSafeIntegerDouble = 9007199254740991.0;

  const _DeepLinkIntegerValue._();

  /// Mirrors runtime module int-param readers for generated links: persisted
  /// parameter maps may carry slider-originated doubles, but generated URLs
  /// must contain replayable integer query values.
  static int? tryParse(Object? value) {
    return switch (value) {
      int v => v,
      double v when _isSafeIntegerDouble(v) => v.round(),
      _ => null,
    };
  }

  static bool _isSafeIntegerDouble(double value) {
    return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
  }
}

/// Mapping between public deep-link Julia aliases and runtime module params.
///
/// Share URLs use compact, stable query names (`juliaX`/`juliaY`), while
/// render modules expose controls as `juliaCReal`/`juliaCImag`. Keeping the
/// mapping explicit prevents generated links and applied deep links from
/// silently dropping Julia constants.
class _DeepLinkJuliaConstantParams {
  static const String urlReal = 'juliaX';
  static const String urlImaginary = 'juliaY';
  static const String runtimeReal = 'juliaCReal';
  static const String runtimeImaginary = 'juliaCImag';

  const _DeepLinkJuliaConstantParams._();

  static void addRuntimeParams(
    Map<String, Object> params, {
    required double? real,
    required double? imaginary,
  }) {
    if (real != null) params[runtimeReal] = real;
    if (imaginary != null) params[runtimeImaginary] = imaginary;
  }

  /// Generated links should prefer actual runtime parameter names but still
  /// accept already URL-shaped maps for compatibility with existing callers.
  static Object? realValueForBuild(Map<String, Object> params) {
    return params[runtimeReal] ?? params[urlReal];
  }

  static Object? imaginaryValueForBuild(Map<String, Object> params) {
    return params[runtimeImaginary] ?? params[urlImaginary];
  }
}

class _DeepLinkViewQueryBounds {
  // Mirrors the controller's default minimum zoom so generated links can
  // replay valid zoomed-out views instead of dropping them back to 1.0x.
  static const double minReplayableZoom = 1e-9;

  // Keep the legacy accepted upper cap for inbound links; generated links still
  // omit out-of-range values rather than minting clamped camera state.
  static const double maxAcceptedZoom = 1e15;
  static const double minCoordinate = -1e10;
  static const double maxCoordinate = 1e10;

  const _DeepLinkViewQueryBounds._();
}

class DeepLinkService {
  static const String scheme = 'fractalforge';
  static const String host = 'view';

  static const _zoomParam = _BoundedDoubleQueryParam(
    'zoom',
    _DeepLinkViewQueryBounds.minReplayableZoom,
    _DeepLinkViewQueryBounds.maxAcceptedZoom,
  );
  static const _xParam = _BoundedDoubleQueryParam(
    'x',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _yParam = _BoundedDoubleQueryParam(
    'y',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _rotXParam = _BoundedDoubleQueryParam(
    'rotX',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _rotYParam = _BoundedDoubleQueryParam(
    'rotY',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _rotZParam = _BoundedDoubleQueryParam(
    'rotZ',
    _DeepLinkViewQueryBounds.minCoordinate,
    _DeepLinkViewQueryBounds.maxCoordinate,
  );
  static const _iterationsParam = _BoundedIntQueryParam('iterations', 1, 10000);
  static const _bailoutParam = _BoundedDoubleQueryParam('bailout', 1.0, 1e10);
  static const _colorSchemeParam =
      _BoundedIntQueryParam('colorScheme', 0, 9999);
  static const _powerParam = _BoundedDoubleQueryParam('power', 1, 20);
  static const _juliaXParam = _BoundedDoubleQueryParam(
    _DeepLinkJuliaConstantParams.urlReal,
    -1e10,
    1e10,
  );
  static const _juliaYParam = _BoundedDoubleQueryParam(
    _DeepLinkJuliaConstantParams.urlImaginary,
    -1e10,
    1e10,
  );

  /// Keeps common Vector3 float32 artifacts (for example `0.3` becoming
  /// `0.3000000119`) from leaking into share URLs while still preserving
  /// rotation values where six-decimal formatting would visibly change input.
  static const double _rotationCompactTolerance = 5e-8;

  static const List<_DeepLinkQueryParamContract> _allQueryParams = [
    _zoomParam,
    _xParam,
    _yParam,
    _rotXParam,
    _rotYParam,
    _rotZParam,
    _iterationsParam,
    _bailoutParam,
    _colorSchemeParam,
    _powerParam,
    _juliaXParam,
    _juliaYParam,
  ];

  // Method channel for receiving deep links from native code
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/deeplink');

  final StreamController<DeepLinkData> _linkController =
      StreamController<DeepLinkData>.broadcast();

  /// Stream of parsed deep link data.
  Stream<DeepLinkData> get linkStream => _linkController.stream;

  DeepLinkData? _initialLink;

  /// The initial deep link that launched the app (if any).
  DeepLinkData? get initialLink => _initialLink;

  /// Initializes the deep link service.
  ///
  /// Sets up listeners for incoming deep links from the platform.
  Future<void> initialize() async {
    // TEMPORARY SAFETY SWITCH (2026-02): deep link channel init causes a black screen
    // on some Samsung S24 devices during startup.
    // User confirmed deep links are not needed for the immediate release.
    // We leave parsing + stream support intact for later re-enable.
    const bool kEnableDeepLinks =
        bool.fromEnvironment('ENABLE_DEEP_LINKS', defaultValue: false);
    if (!kEnableDeepLinks) {
      return;
    }

    // Set up method channel handler for incoming links
    _channel.setMethodCallHandler(_handleMethodCall);

    // Try to get the initial link that launched the app
    try {
      final Object? initialUri = await _channel.invokeMethod('getInitialLink');
      final data = parseIncomingLink(initialUri);
      if (data != null) {
        _initialLink = data;
      }
    } on PlatformException {
      // Platform doesn't support deep links or no initial link
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    if (call.method == 'onDeepLink') {
      final data = parseIncomingLink(call.arguments);
      if (data != null) {
        _linkController.add(data);
      }
    }
  }

  /// Parses a platform-provided deep-link payload into [DeepLinkData].
  ///
  /// Native channels are expected to send URI strings, but malformed payloads
  /// are ignored instead of crashing the method-channel handler.
  static DeepLinkData? parseIncomingLink(
    Object? link, {
    List<String>? validFractalTypes,
  }) {
    if (link is! String || link.isEmpty) {
      return null;
    }

    try {
      return parseUri(
        Uri.parse(link),
        validFractalTypes: validFractalTypes,
      );
    } catch (e) {
      // Malformed URI, ignore.
      if (kDebugMode) debugPrint('Failed to parse deep link URI: $e');
      return null;
    }
  }

  /// Parses a URI into [DeepLinkData].
  ///
  /// Returns null if the URI is not a valid fractalforge deep link or
  /// if the fractal type is not recognized.
  static DeepLinkData? parseUri(Uri uri, {List<String>? validFractalTypes}) {
    final route = _DeepLinkRoute.fromUri(uri);
    if (!route.isAccepted) {
      return null;
    }

    final _DeepLinkQuery query;
    try {
      query = _DeepLinkQuery.fromUri(uri);
    } on FormatException catch (e) {
      if (kDebugMode) debugPrint('DeepLink: ${e.message} — rejecting link');
      return null;
    }

    final type = query['type'];

    if (type == null || type.isEmpty) {
      return null;
    }

    // Reject type strings with unsafe characters (defense-in-depth).
    if (!_DeepLinkModuleId.isSafe(type)) {
      return null;
    }

    // Validate fractal type if validation list provided
    if (validFractalTypes != null && !validFractalTypes.contains(type)) {
      return null;
    }

    return DeepLinkData(
      type: type,
      zoom: _zoomParam.parse(query),
      x: _xParam.parse(query),
      y: _yParam.parse(query),
      rotX: _rotXParam.parse(query),
      rotY: _rotYParam.parse(query),
      rotZ: _rotZParam.parse(query),
      iterations: _iterationsParam.parse(query),
      bailout: _bailoutParam.parse(query),
      colorScheme: _colorSchemeParam.parse(query),
      power: _powerParam.parse(query),
      juliaX: _juliaXParam.parse(query),
      juliaY: _juliaYParam.parse(query),
    );
  }

  /// Builds a shareable deep link URL from the current fractal state.
  ///
  /// The [moduleId] specifies the fractal type, [params] contains the
  /// fractal parameters, and [view] contains the camera/view state.
  static Uri buildUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final queryParams = <String, String>{
      'type': _DeepLinkModuleId.requireSafeForBuild(moduleId),
    };

    _addViewStateQueryParams(queryParams, view);

    // Add fractal parameters. Unsupported values are omitted rather than
    // converted to sentinel values that parse back as valid-but-wrong params.
    _addBoundedIntQueryParam(
        queryParams, _iterationsParam, params['iterations']);
    _addBoundedDoubleQueryParam(queryParams, _bailoutParam, params['bailout']);
    _addBoundedIntQueryParam(
      queryParams,
      _colorSchemeParam,
      params['colorScheme'],
    );
    _addBoundedDoubleQueryParam(queryParams, _powerParam, params['power']);
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaXParam,
      _DeepLinkJuliaConstantParams.realValueForBuild(params),
      preservePrecision: true,
    );
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaYParam,
      _DeepLinkJuliaConstantParams.imaginaryValueForBuild(params),
      preservePrecision: true,
    );

    return Uri(
      scheme: scheme,
      host: host,
      queryParameters: queryParams,
    );
  }

  /// Adds view-state fields to generated links.
  ///
  /// View state is one replay contract: zoom, pan, and 3D rotation values all
  /// need significant digits preserved so shared links restore the same camera
  /// instead of a rounded approximation.
  static void _addViewStateQueryParams(
    Map<String, String> queryParams,
    FractalViewState view,
  ) {
    // Use the same bounded contracts as parsing so generated links do not
    // round-trip through clamped or invalid camera values.
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _zoomParam,
      view.zoom,
      defaultValue: 1.0,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _xParam,
      view.pan.x,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _yParam,
      view.pan.y,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _rotXParam,
      view.rotation.x,
      preservePrecision: true,
      compactTolerance: _rotationCompactTolerance,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _rotYParam,
      view.rotation.y,
      preservePrecision: true,
      compactTolerance: _rotationCompactTolerance,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _rotZParam,
      view.rotation.z,
      preservePrecision: true,
      compactTolerance: _rotationCompactTolerance,
    );
  }

  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = int.tryParse(v);
    if (i == null) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(
    double value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    // Keep integer-looking values compact without truncating significant deep-zoom
    // view coordinates that need more than six decimal places to round-trip.
    if (value == value.truncateToDouble()) {
      return value.toInt().toString();
    }

    final compactFixed =
        value.toStringAsFixed(6).replaceAll(RegExp(r'\.?0+$'), '');
    final compactValue = double.tryParse(compactFixed);
    final compactWithinTolerance = compactValue != null &&
        compactTolerance > 0.0 &&
        (compactValue - value).abs() <= compactTolerance;
    if (!preservePrecision || compactValue == value || compactWithinTolerance) {
      return compactFixed;
    }

    return value.toString();
  }

  static void _addBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final formatted = param.format(
      value,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static void _addNonDefaultBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    double defaultValue = 0.0,
    bool preservePrecision = false,
    double compactTolerance = 0.0,
  }) {
    final parsed = _tryFiniteDouble(value);
    if (parsed == null || parsed == defaultValue) return;
    _addBoundedDoubleQueryParam(
      queryParams,
      param,
      parsed,
      preservePrecision: preservePrecision,
      compactTolerance: compactTolerance,
    );
  }

  static void _addBoundedIntQueryParam(
    Map<String, String> queryParams,
    _BoundedIntQueryParam param,
    Object? value,
  ) {
    final formatted = param.format(value);
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static double? _tryFiniteDouble(Object? value) {
    final parsed = switch (value) {
      double v => v,
      int v => v.toDouble(),
      String v => double.tryParse(v),
      _ => null,
    };
    if (parsed == null || parsed.isNaN || parsed.isInfinite) {
      return null;
    }
    return parsed;
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

